import React, { useState } from "react";
import { Link } from "react-router-dom";

export default function Register() {
  const [firstName, setFirstName] = useState("");
  const [lastName, setLastName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [birthPlace, setBirthPlace] = useState("");
  const [birthDate, setBirthDate] = useState("");
  const [role, setRole] = useState("");

  const [firstNameError, setFirstNameError] = useState(false);
  const [lastNameError, setLastNameError] = useState(false);
  const [emailError, setEmailError] = useState(false);
  const [passwordError, setPasswordError] = useState(false);
  const [birthPlaceError, setBirthPlaceError] = useState(false);
  const [birthDateError, setBirthDateError] = useState(false);
  const [roleError, setRoleError] = useState(false);

  const [buttonText, setButtonText] = useState("Create Account");

  const validateForm = () => {
    let isValid = true;

    if (!firstName || firstName.trim().length < 2) {
      setFirstNameError(true);
      isValid = false;
    } else {
      setFirstNameError(false);
    }

    if (!lastName || lastName.trim().length < 2) {
      setLastNameError(true);
      isValid = false;
    } else {
      setLastNameError(false);
    }

    if (!email || !email.includes("@") || !email.includes(".")) {
      setEmailError(true);
      isValid = false;
    } else {
      setEmailError(false);
    }

    if (!password || password.length < 6) {
      setPasswordError(true);
      isValid = false;
    } else {
      setPasswordError(false);
    }

    if (!birthPlace || birthPlace.trim().length < 2) {
      setBirthPlaceError(true);
      isValid = false;
    } else {
      setBirthPlaceError(false);
    }

    if (!birthDate) {
      setBirthDateError(true);
      isValid = false;
    } else {
      setBirthDateError(false);
    }

    if (!role) {
      setRoleError(true);
      isValid = false;
    } else {
      setRoleError(false);
    }

    return isValid;
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (validateForm()) {
      setButtonText("Creating Account...");
      setTimeout(() => {
        alert(`Welcome ${role === "manager" ? "Manager" : "Worker"}! Registration successful!\n\nName: ${firstName} ${lastName}\nEmail: ${email}\nBirth Place: ${birthPlace}\nBirth Date: ${birthDate}`);
        setButtonText("Create Account");
      }, 1000);
    } else {
      setButtonText("❌ Complete all fields!");
      setTimeout(() => {
        setButtonText("Create Account");
      }, 1500);
    }
  };

  const handleRoleSelect = (selectedRole) => {
    setRole(selectedRole);
    if (roleError) setRoleError(false);
  };

  return (
    <div className="relative w-full min-h-screen" style={{
      background: "linear-gradient(135deg, #14532d 0%, #000000 50%, #14532d 100%)",
    }}>
      <div className="flex items-center justify-center min-h-screen">
        <div className="w-full max-w-md p-6 bg-black/50 rounded-2xl border border-green-500/30 backdrop-blur-sm mt-12">
          {/* Join Us Title */}
          <div className="text-center mb-6">
            <h1 className="text-5xl font-bold text-white mb-2">
              Join Us
            </h1>
            <div className="w-24 h-1 bg-green-500 mx-auto rounded-full"></div>
          </div>

          <h2 className="text-3xl text-white text-center mb-2">Register</h2>
          <p className="text-white/60 text-center text-sm mb-6">Create your account to get started</p>

          <form onSubmit={handleSubmit}>
            {/* First Name */}
            <div className="mb-4">
              <label className="block text-white text-sm font-semibold mb-1">First Name</label>
              <input 
                type="text" 
                placeholder="John" 
                value={firstName} 
                onChange={(e)=>setFirstName(e.target.value)} 
                className={`custom-input ${firstNameError ? "border-red-500" : "border-green-800"}`} 
              />
              {firstNameError && <p className="text-red-400 text-xs mt-1">⚠️ First name is required</p>}
            </div>

            {/* Last Name */}
            <div className="mb-4">
              <label className="block text-white text-sm font-semibold mb-1">Last Name</label>
              <input 
                type="text" 
                placeholder="Doe" 
                value={lastName} 
                onChange={(e)=>setLastName(e.target.value)} 
                className={`custom-input ${lastNameError ? "border-red-500" : "border-green-800"}`} 
              />
              {lastNameError && <p className="text-red-400 text-xs mt-1">⚠️ Last name is required</p>}
            </div>

            {/* Email */}
            <div className="mb-4">
              <label className="block text-white text-sm font-semibold mb-1">Email</label>
              <input 
                type="email" 
                placeholder="your@email.com" 
                value={email} 
                onChange={(e)=>setEmail(e.target.value)} 
                className={`custom-input ${emailError ? "border-red-500" : "border-green-800"}`} 
              />
              {emailError && <p className="text-red-400 text-xs mt-1">⚠️ Please enter a valid email address</p>}
            </div>

            {/* Birth Place */}
            <div className="mb-4">
              <label className="block text-white text-sm font-semibold mb-1">Birth Place</label>
              <input 
                type="text" 
                placeholder="City, Country" 
                value={birthPlace} 
                onChange={(e)=>setBirthPlace(e.target.value)} 
                className={`custom-input ${birthPlaceError ? "border-red-500" : "border-green-800"}`} 
              />
              {birthPlaceError && <p className="text-red-400 text-xs mt-1">⚠️ Birth place is required</p>}
            </div>

            {/* Birth Date */}
            <div className="mb-4">
              <label className="block text-white text-sm font-semibold mb-1">Birth Date</label>
              <input 
                type="date" 
                value={birthDate} 
                onChange={(e)=>setBirthDate(e.target.value)} 
                className={`custom-input ${birthDateError ? "border-red-500" : "border-green-800"}`} 
                style={{ colorScheme: "dark" }}
              />
              {birthDateError && <p className="text-red-400 text-xs mt-1">⚠️ Birth date is required</p>}
            </div>

            {/* Password */}
            <div className="mb-4">
              <label className="block text-white text-sm font-semibold mb-1">Password</label>
              <input 
                type="password" 
                placeholder="••••••••" 
                value={password} 
                onChange={(e)=>setPassword(e.target.value)} 
                className={`custom-input ${passwordError ? "border-red-500" : "border-green-800"}`} 
              />
              {passwordError && <p className="text-red-400 text-xs mt-1">⚠️ Password must be at least 6 characters</p>}
            </div>

            {/* Role Selection */}
            <div className="mb-6">
              <label className="block text-white text-sm font-semibold mb-3">Register as:</label>
              <div className="flex gap-4">
                <button
                  type="button"
                  onClick={() => handleRoleSelect("manager")}
                  className={`
                    flex-1 flex items-center justify-center gap-2 px-4 py-3 rounded-xl 
                    transition-all duration-300 font-semibold
                    ${role === "manager" 
                      ? "bg-green-600 text-white shadow-lg scale-105" 
                      : "bg-white/10 text-white/80 hover:bg-white/20 border border-white/20"}
                  `}
                >
                  <i className="fas fa-chart-line text-lg"></i>
                  <span>Manager</span>
                </button>

                <button
                  type="button"
                  onClick={() => handleRoleSelect("worker")}
                  className={`
                    flex-1 flex items-center justify-center gap-2 px-4 py-3 rounded-xl 
                    transition-all duration-300 font-semibold
                    ${role === "worker" 
                      ? "bg-green-600 text-white shadow-lg scale-105" 
                      : "bg-white/10 text-white/80 hover:bg-white/20 border border-white/20"}
                  `}
                >
                  <i className="fas fa-tools text-lg"></i>
                  <span>Worker</span>
                </button>
              </div>
              {roleError && <p className="text-red-400 text-xs mt-2">⚠️ Please select a role</p>}
            </div>

            {/* Terms & Conditions */}
            <div className="mb-6">
              <label className="inline-flex items-center cursor-pointer">
                <input
                  type="checkbox"
                  className="form-checkbox rounded text-green-500 w-5 h-5 bg-white/20 border-white/30"
                />
                <span className="ml-2 text-sm font-semibold text-white/80">
                  I agree with the{" "}
                  <a href="#pablo" className="text-green-400 hover:text-green-300" onClick={(e) => e.preventDefault()}>
                    Privacy Policy
                  </a>
                </span>
              </label>
            </div>

            {/* Submit Button */}
            <button 
              type="submit" 
              className="w-full bg-green-700 hover:bg-green-600 text-white font-bold uppercase py-3 rounded-2xl shadow-xl hover:shadow-2xl transition-all duration-300"
            >
              {buttonText}
            </button>

            {/* Sign In Link */}
            <p className="text-white/60 text-sm mt-6 text-center">
              Already have an account?{" "}
              <Link to="/auth/login" className="text-green-400 hover:text-green-300 font-semibold">
                Sign In
              </Link>
            </p>
          </form>
        </div>
      </div>

      <style>{`
        .custom-input {
          width: 100%;
          padding: 12px 0;
          background: transparent;
          border: none;
          border-bottom: 2px solid #2e7d32;
          color: white;
          font-size: 16px;
          outline: none;
          box-shadow: none;
          transition: all 0.3s ease;
        }

        .custom-input:focus {
          border-bottom: 2px solid #00d8d0;
          outline: none;
          box-shadow: none;
        }

        input:focus,
        input:focus-visible {
          outline: none !important;
          box-shadow: none !important;
        }

        /* إضافة تأثير التوهج */
        .custom-input {
          position: relative;
        }

        /* تنسيق أيقونات FontAwesome */
        .fas, .fab {
          font-family: "Font Awesome 6 Free";
        }
      `}</style>
    </div>
  );
}
